/** Ninja upgrade purchase cost — the "JadeUpgCost"==d dispatcher case (misleadingly named;
 * it's actually the NINJA UPGRADE cost, not a jade emporium cost), N.js:17984-18016 (long
 * single statement, read in full). Verbatim structure: a shared prefix factor
 *   `1/(1+NinjaBonus(11,-1)/100) / ((1+NLbonuses(1,0)/100)*(1+GemstoneBonus(6,0)/100)*(1+TalentCalc(430)/100))`
 * (all-upgrade-cost-reduction sources: Charm_Collector item bonus id 11, Way_of_Bargain
 * (NLbonuses(1,0)), Emerald gemstone (GemstoneBonus(6,0)), and a class talent id 430),
 * a per-100-levels discount factor `1/(1+NLbonuses(0,0)/100)^floor(level/100)` (Centurion_Lineage),
 * then a BESPOKE per-upgrade-index formula selecting among several `Math.pow` growth curves —
 * most upgrades use the plain `costBase * costGrowth^level` form implemented below; upgrades
 * 0, 1, 3, 4, 8, 13 have their own special-cased curves (extra discount factors, alternate
 * exponent bases) NOT reproduced here — this function covers the DEFAULT branch only (all
 * upgrades except 0/1/3/4/8/13) and is UNVERIFIED for those six ids. Use NINJA_UPGRADES[b] for
 * base cost display; treat this function as a rough default, not authoritative for every id. */
export function ninjaUpgradeCostDefault(b, level, mods = {}) {
  const row = NINJA_UPGRADES[b];
  if (!row) throw new Error(`ninjaUpgradeCostDefault(${b}): unknown upgrade index`);
  const {
    ninjaBonus11 = 0, // NinjaBonus(11,-1) — equipped Charm item cost-reduction sum
    nlBonus1 = 0,     // NLbonuses(1,0) — Way_of_Bargain
    gemstoneBonus6 = 0, // GemstoneBonus(6,0) — Emerald
    talent430 = 0,    // TalentCalc(430) — class talent, out of scope here
    nlBonus0 = 0,     // NLbonuses(0,0) — Centurion_Lineage
  } = mods;
  const prefix = (1 / (1 + ninjaBonus11 / 100)) / ((1 + nlBonus1 / 100) * (1 + gemstoneBonus6 / 100) * (1 + talent430 / 100));
  const per100 = 1 / Math.pow(1 + nlBonus0 / 100, Math.floor(level / 100));
  return prefix * row.costBase * Math.pow(row.costGrowth, level) * per100;
}

/** Ninja upgrade BONUS VALUE — the "NLbonuses"==d dispatcher case, VERBATIM, N.js:18016-18018:
 *   99==b ? 1
 *   : 11==b ? round( level*modifier
 *       + ( masteryLootLevel*selectedMasteryLevel
 *         + ( NinjaBonus(21,-1)
 *           + ( ceil(GemstoneBonus(7,0))
 *             + floor( PaletteBonus(30,0) + (VaultUpgBonus(88,0) + 100*CloudBonus(53)) )
 *           )
 *         )
 *       )
 *     )
 *   : (6==b||7==b||10==b||12==b) ? level*modifier + masteryLootLevel*selectedMasteryLevel
 *   : level*modifier
 * where level = Ninja[103][b], modifier = NinjaUpg[b][5], masteryLootLevel = Ninja[103][3]
 * (Mastery_Loot's own level), selectedMasteryLevel = OptionsListAccount[231].
 *
 * DISCREPANCY vs idleon-toolbox's sneaking.ts:245-251 `getLocalNinjaUpgradeBonus` (index===11
 * branch): toolbox has `+goldStar +ceil(fireFrostBonus) +floor(paletteBonus30+vaultBonus88)` —
 * it is MISSING the `100*CloudBonus(53)` term entirely (an Equinox-dream bonus contribution)
 * inside the floor(...), even though its `goldStar`/`fireFrostBonus`/`paletteBonus30`/
 * `vaultBonus88` names line up with N.js's `NinjaBonus(21,-1)`/`GemstoneBonus(7,0)`/
 * `PaletteBonus(30,0)`/`VaultUpgBonus(88,0)` respectively. Transcribed VERBATIM below per N.js;
 * the `cloudBonus53` term is exposed as a parameter so callers can supply 0 until Equinox dream
 * 53's bonus is wired up elsewhere (out of scope for this file). */
export function ninjaUpgradeBonus(b, ctx = {}) {
  const {
    level = 0, modifier = 1, masteryLootLevel = 0, selectedMasteryLevel = 0,
    ninjaBonus21 = 0, gemstoneBonus7 = 0, paletteBonus30 = 0, vaultUpgBonus88 = 0, cloudBonus53 = 0,
  } = ctx;
  if (b === 99) return 1;
  if (b === 11) {
    return Math.round(
      level * modifier
      + (masteryLootLevel * selectedMasteryLevel
        + (ninjaBonus21
          + (Math.ceil(gemstoneBonus7)
            + Math.floor(paletteBonus30 + (vaultUpgBonus88 + 100 * cloudBonus53)))))
    );
  }
  if (b === 6 || b === 7 || b === 10 || b === 12) {
    return level * modifier + masteryLootLevel * selectedMasteryLevel;
  }
  return level * modifier;
}

