/** Gemstone bonus — the "GemstoneBonus"==d dispatcher case, VERBATIM, N.js:17970-17972:
 *   .5 < OptionsListAccount[233+b] ?
 *     ( 5==b
 *         ? NjGem[b].x3 + NjGem[b].x5 * (baseValue/(1000+baseValue))
 *         : (NjGem[b].x3 + NjGem[b].x5 * (baseValue/(1000+baseValue)))
 *             * (1 + GemstoneBonus(5,0)/100)
 *             * Math.max(1, _customBlock_getbonus2(1,432,-1))   // Wind Walker talent 432
 *     )
 *     : 0
 * where baseValue = OptionsListAccount[233+b] (accountOptions[233+idx]). Gate: baseValue must
 * exceed 0.5 or the bonus is a flat 0 (matches toolbox's `baseValue < .5 ? 0 : ...` exactly).
 * `talentBonus` = getHighestTalentByClass(Wind_Walker, 'GENERATIONAL_GEMSTONES') per toolbox —
 * confirmed the N.js call site is `_customBlock_getbonus2(1,432,-1)`, talent id 432; the talent
 * system itself is out of scope for this file. */
export function gemstoneBonus(idx, baseValue, ctx = {}) {
  const row = GEMSTONES[idx];
  if (!row) throw new Error(`gemstoneBonus(${idx}): unknown gemstone index`);
  if (!(baseValue > 0.5)) return 0;
  const raw = row.x3 + row.x5 * (baseValue / (1000 + baseValue));
  if (idx === 5) return raw;
  const { fifthGemstoneBonus = 0, talentBonus = 0 } = ctx;
  return raw * (1 + fifthGemstoneBonus / 100) * Math.max(1, talentBonus);
}

