/** Detection rate multiplier — the "DetectionDEC"==d dispatcher case, VERBATIM, N.js:17983-17984:
 *   floorDetection = NinjaInfo[9][floor]   // FLOOR_DETECTION_BASE[floor]
 *   return Math.max(0, Math.min(1, 1 - 1.1 * Stealth(b,e) / (Stealth(b,e) + floorDetection)))
 * A diminishing-returns curve clamped to [0,1]: at Stealth=0 this returns 1 (no detection
 * decrease at all); as Stealth grows relative to the floor's base detection value, the result
 * shrinks toward (and can hit) 0. The `1.1x` numerator coefficient means detection can be
 * over-suppressed once Stealth is roughly >= 10x the floor's base detection value (the ratio
 * term alone would need Stealth/(Stealth+floorDetection) > 1/1.1 ≈ 0.909, i.e.
 * Stealth > ~10*floorDetection, for the min(1,...) clamp to bind at 0). */
export function detectionRateMultiplier(stealth, floor) {
  const floorDetection = FLOOR_DETECTION_BASE[floor];
  if (floorDetection === undefined) throw new Error(`detectionRateMultiplier: unknown floor ${floor} (valid range 0-11)`);
  return Math.max(0, Math.min(1, 1 - (1.1 * stealth) / (stealth + floorDetection)));
}

/** ------------------------------------------------------------------------------------------
 * 7. GACHA — pristine-charm (and adjacent symbol) roll chance, inside the "GenerateItem"==d
 * dispatcher case, VERBATIM, N.js:18022 (read in the surrounding ~2KB window):
 *
 *   c.randomFloat() < .001 * Math.max(0, 1.5 - OptionsListAccount[402]/80)
 *                    * (1 + CompassBonus(54,0)/100)
 *   -> on success: b = c.randomInt(0,22); grant NjTrP{b}
 *
 * EXACT VERBATIM MATCH to idleon-toolbox's sneaking.ts:205-206 `pristineCharmChance` — 0
 * discrepancy. `OptionsListAccount[402]` = the "charm roll counter" (toolbox's
 * `charmRollCounter`, resets daily per the surrounding roll-tracking logic — not re-verified in
 * this pass). The `c.randomInt(0,22)` call is the SECOND independent confirmation (after the
 * NjTrP0-22 grep sweep) that there are exactly 23 pristine charms, not ~40.
 *
 * RECONCILIATION vs the task brief's "chance decay 0.1%->0.001%" framing: that framing is
 * WRONG. Plugging the formula's own range in: at counter=0, chance = .001*1.5 = 0.0015 = 0.15%
 * (not 0.1%); at counter=80, chance = .001*max(0,1.5-1)=.001*0.5=0.0005=0.05%; at counter>=120,
 * chance = .001*max(0,1.5-1.5)=0 = 0% (matches idleon-toolbox's own
 * `remainingPristineRolls = max(0,120-charmRollCounter)` reaching 0 exactly at counter=120).
 * The TRUE range is 0.15% (counter=0) decaying LINEARLY to 0% (counter>=120), not the "0.1% to
 * 0.001%" the brief describes — that older framing appears to conflate this with a different
 * (possibly outdated or symbol-roll) formula; the ACTUAL live N.js formula is transcribed above
 * with zero ambiguity.
 * ------------------------------------------------------------------------------------------ */
export function gachaPristineCharmChance(charmRollCounter, compassBonus54 = 0) {
  return 0.001 * Math.max(0, 1.5 - charmRollCounter / 80) * (1 + compassBonus54 / 100);
}

export function gachaPristineRollsRemaining(charmRollCounter) {
  return Math.max(0, 120 - charmRollCounter);
}

export function gachaSymbolRollsRemaining(charmRollCounter) {
  return Math.max(0, 75 - charmRollCounter);
}

